import{_ as a}from"./plugin-vue_export-helper-DlAUqK2U.js";import{c as l,a as s,e as n,r as o,o as r}from"./app-MOk6SBbl.js";const i={};function p(d,e){const t=o("Mermaid");return r(),l("div",null,[e[0]||(e[0]=s(`<h2 id="引言" tabindex="-1"><a class="header-anchor" href="#引言"><span>引言</span></a></h2><p>MySQL 性能上不去？先查这 5 个瓶颈点。一条慢 SQL，可能卡在执行计划的索引选择、也可能耗在磁盘 I/O、甚至被锁竞争拖垮。你只用 EXPLAIN 看执行计划？如果执行计划没问题但查询依然慢呢？</p><p>本文带你系统学习 MySQL 性能诊断的核心工具和方法，从 CPU、内存、磁盘 I/O、网络到锁竞争，逐一拆解瓶颈定位思路。读完本文你将掌握：</p><ul><li><strong>Profile 工具的使用与局限</strong>：MySQL 提供的性能分析利器，以及为什么在 8.0 中已被弃用</li><li><strong>SQL 性能分析全流程</strong>：从慢查询日志 → Profile → performance_schema → EXPLAIN 的完整诊断链路</li><li><strong>替代方案</strong>：Performance Schema 和 sys schema 如何接棒 Profile 成为新一代性能分析工具</li></ul><h2 id="profile-配置与开启" tabindex="-1"><a class="header-anchor" href="#profile-配置与开启"><span>Profile 配置与开启</span></a></h2><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">SHOW</span> VARIABLES <span class="token operator">LIKE</span> <span class="token string">&#39;%profil%&#39;</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>输出参数详解：</p><ul><li><strong>have_profiling</strong>：表示是否支持 Profile 功能，YES 表示支持</li><li><strong>profiling</strong>：表示是否开启 Profile 功能，ON 开启，OFF 关闭，默认是关闭状态</li><li><strong>profiling_history_size</strong>：表示保存最近 15 条历史数据</li></ul><h3 id="开启-profile-功能" tabindex="-1"><a class="header-anchor" href="#开启-profile-功能"><span>开启 Profile 功能</span></a></h3><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">SET</span> profiling <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>注意：修改配置只对当前会话生效，会话关闭后 Profile 历史信息被清空。</p><h2 id="使用-profile-分析-sql-性能" tabindex="-1"><a class="header-anchor" href="#使用-profile-分析-sql-性能"><span>使用 Profile 分析 SQL 性能</span></a></h2><p>先造点数据，创建一张用户表：</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> <span class="token identifier"><span class="token punctuation">\`</span>user<span class="token punctuation">\`</span></span> <span class="token punctuation">(</span>
  <span class="token identifier"><span class="token punctuation">\`</span>id<span class="token punctuation">\`</span></span> <span class="token keyword">int</span><span class="token punctuation">(</span><span class="token number">11</span><span class="token punctuation">)</span> <span class="token operator">NOT</span> <span class="token boolean">NULL</span> <span class="token keyword">AUTO_INCREMENT</span> <span class="token keyword">COMMENT</span> <span class="token string">&#39;主键ID&#39;</span><span class="token punctuation">,</span>
  <span class="token identifier"><span class="token punctuation">\`</span>name<span class="token punctuation">\`</span></span> <span class="token keyword">varchar</span><span class="token punctuation">(</span><span class="token number">100</span><span class="token punctuation">)</span> <span class="token operator">NOT</span> <span class="token boolean">NULL</span> <span class="token keyword">DEFAULT</span> <span class="token string">&#39;&#39;</span> <span class="token keyword">COMMENT</span> <span class="token string">&#39;姓名&#39;</span><span class="token punctuation">,</span>
  <span class="token identifier"><span class="token punctuation">\`</span>age<span class="token punctuation">\`</span></span> <span class="token keyword">tinyint</span> <span class="token operator">NOT</span> <span class="token boolean">NULL</span> <span class="token keyword">DEFAULT</span> <span class="token number">0</span><span class="token punctuation">,</span>
  <span class="token keyword">PRIMARY</span> <span class="token keyword">KEY</span> <span class="token punctuation">(</span><span class="token identifier"><span class="token punctuation">\`</span>id<span class="token punctuation">\`</span></span><span class="token punctuation">)</span>
<span class="token punctuation">)</span> <span class="token keyword">ENGINE</span><span class="token operator">=</span><span class="token keyword">InnoDB</span> <span class="token keyword">DEFAULT</span> <span class="token keyword">CHARSET</span><span class="token operator">=</span>utf8mb4<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>执行一条耗时 SQL：</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> <span class="token keyword">user</span> <span class="token keyword">ORDER</span> <span class="token keyword">BY</span> name<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>下面轮到主角 <strong>Profile</strong> 出场了。我们执行的所有 SQL 语句都会被记录到 Profile 里面，包括执行失败的 SQL 语句。使用 <code>show profiles</code> 命令查看：</p><table><thead><tr><th style="text-align:left;">参数</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Query_ID</strong></td><td style="text-align:left;">自动分配的查询 ID，顺序递增</td></tr><tr><td style="text-align:left;"><strong>Duration</strong></td><td style="text-align:left;">SQL 语句执行耗时</td></tr><tr><td style="text-align:left;"><strong>Query</strong></td><td style="text-align:left;">SQL 语句内容</td></tr></tbody></table><p>然后使用 Query_ID 查看具体每一步的耗时情况：</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">SHOW</span> PROFILE <span class="token keyword">FOR</span> QUERY <span class="token number">1</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>可以清楚地看到耗时主要花在 <strong>创建排序索引（Creating sort index）</strong> 上面。</p><p>再试一条 SQL：</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token keyword">DISTINCT</span> name <span class="token keyword">FROM</span> <span class="token keyword">user</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>这次的耗时主要花在了：创建临时文件、拷贝文件到磁盘、发送数据、删除临时表上面。由此可以得知 <code>DISTINCT</code> 操作会创建临时文件，提醒我们需要建合适的索引来避免。</p><p>还可以扩展分析语句，查看 CPU 和 Block I/O 的使用情况：</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">SHOW</span> PROFILE CPU<span class="token punctuation">,</span> BLOCK IO <span class="token keyword">FOR</span> QUERY <span class="token number">2</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>所有 Profile 历史数据都被记录在 <code>information_schema.profiling</code> 表中，也可以直接查询：</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> information_schema<span class="token punctuation">.</span>profiling <span class="token keyword">WHERE</span> Query_ID <span class="token operator">=</span> <span class="token number">2</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><blockquote><p><strong>💡 核心提示</strong>：<code>SHOW PROFILE</code> 可以精确到 SQL 执行的每个阶段（如 Opening tables、Creating tmp table、Sorting result 等），帮助你精准定位性能瓶颈。但这些数据仅在当前会话内有效，会话关闭即清空。</p></blockquote><h2 id="mysql-8-0-中的替代方案" tabindex="-1"><a class="header-anchor" href="#mysql-8-0-中的替代方案"><span>MySQL 8.0 中的替代方案</span></a></h2><p>以上数据基于 MySQL 5.7 版本。细心的你可能已经发现，每执行完一条 SQL 都会出现一条 warning 信息：</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">SHOW</span> <span class="token keyword">WARNINGS</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>意思就是 <strong>Profile 工具将来有可能被删除，不建议继续使用了</strong>。在 MySQL 8.0 中，Profile 已被标记为废弃（deprecated），推荐使用 <strong>Performance Schema</strong> 和 <strong>sys schema</strong> 作为替代方案。</p>`,33)),n(t,{id:"mermaid-146",code:""}),e[1]||(e[1]=s(`<h3 id="performance-schema-常用查询" tabindex="-1"><a class="header-anchor" href="#performance-schema-常用查询"><span>Performance Schema 常用查询</span></a></h3><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token comment">-- 查看最近执行的 SQL 及其耗时</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> performance_schema<span class="token punctuation">.</span>events_statements_history <span class="token keyword">ORDER</span> <span class="token keyword">BY</span> TIMER_WAIT <span class="token keyword">DESC</span> <span class="token keyword">LIMIT</span> <span class="token number">10</span><span class="token punctuation">;</span>

<span class="token comment">-- 查看等待事件</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> performance_schema<span class="token punctuation">.</span>events_waits_summary_global_by_event_name 
  <span class="token keyword">ORDER</span> <span class="token keyword">BY</span> SUM_TIMER_WAIT <span class="token keyword">DESC</span> <span class="token keyword">LIMIT</span> <span class="token number">10</span><span class="token punctuation">;</span>

<span class="token comment">-- 使用 sys schema 快速定位慢查询</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> sys<span class="token punctuation">.</span>statements_with_runtimes_in_95th_percentile <span class="token keyword">LIMIT</span> <span class="token number">10</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p><strong>💡 核心提示</strong>：Performance Schema 的开销在 MySQL 8.0 中已经大幅优化（默认开启的 instrument 仅带来约 1%~3% 的性能开销），建议在生产环境中长期开启，配合监控告警平台使用。</p></blockquote><h2 id="性能瓶颈诊断决策树" tabindex="-1"><a class="header-anchor" href="#性能瓶颈诊断决策树"><span>性能瓶颈诊断决策树</span></a></h2>`,4)),n(t,{id:"mermaid-159",code:""}),e[2]||(e[2]=s('<h2 id="生产环境避坑指南" tabindex="-1"><a class="header-anchor" href="#生产环境避坑指南"><span>生产环境避坑指南</span></a></h2><table><thead><tr><th style="text-align:left;">坑位</th><th style="text-align:left;">现象</th><th style="text-align:left;">解决方案</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>忽略慢查询日志</strong></td><td style="text-align:left;">不知道哪些 SQL 慢，等用户投诉才发现</td><td style="text-align:left;">开启 <code>slow_query_log</code>，设置 <code>long_query_time=1</code>，定期分析慢查询日志</td></tr><tr><td style="text-align:left;"><strong>Profile 会话级限制</strong></td><td style="text-align:left;">重启或断开连接后历史数据丢失</td><td style="text-align:left;">生产环境改用 Performance Schema 进行持续监控</td></tr><tr><td style="text-align:left;"><strong>Buffer Pool 配置不当</strong></td><td style="text-align:left;">默认值 128MB 远不够生产使用，大量磁盘 I/O</td><td style="text-align:left;">根据服务器内存调整 <code>innodb_buffer_pool_size</code>，建议为物理内存的 60%~80%</td></tr><tr><td style="text-align:left;"><strong>临时表溢出到磁盘</strong></td><td style="text-align:left;">复杂查询触发 tmp table on disk，性能骤降</td><td style="text-align:left;">调整 <code>tmp_table_size</code> 和 <code>max_heap_table_size</code>，优化查询避免不必要的 GROUP BY</td></tr><tr><td style="text-align:left;"><strong>锁等待超时</strong></td><td style="text-align:left;"><code>Lock wait timeout exceeded</code> 频繁出现</td><td style="text-align:left;">缩小事务范围，避免长事务，使用 <code>SHOW ENGINE INNODB STATUS</code> 排查锁等待</td></tr><tr><td style="text-align:left;"><strong>Profile 已废弃仍在使用</strong></td><td style="text-align:left;">升级到 MySQL 8.0 后 Profile 不可用或报 warning</td><td style="text-align:left;">迁移到 Performance Schema 和 sys schema，配置合适的监控采集策略</td></tr></tbody></table><h2 id="总结" tabindex="-1"><a class="header-anchor" href="#总结"><span>总结</span></a></h2><table><thead><tr><th style="text-align:left;">工具</th><th style="text-align:left;">MySQL 版本</th><th style="text-align:left;">精度</th><th style="text-align:left;">持久化</th><th style="text-align:left;">推荐程度</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Profile</strong></td><td style="text-align:left;">5.0 ~ 8.0(废弃)</td><td style="text-align:left;">阶段级</td><td style="text-align:left;">会话级</td><td style="text-align:left;">⭐⭐（已弃用）</td></tr><tr><td style="text-align:left;"><strong>慢查询日志</strong></td><td style="text-align:left;">全版本</td><td style="text-align:left;">语句级</td><td style="text-align:left;">持久化</td><td style="text-align:left;">⭐⭐⭐⭐⭐</td></tr><tr><td style="text-align:left;"><strong>EXPLAIN</strong></td><td style="text-align:left;">全版本</td><td style="text-align:left;">执行计划</td><td style="text-align:left;">-</td><td style="text-align:left;">⭐⭐⭐⭐⭐</td></tr><tr><td style="text-align:left;"><strong>Performance Schema</strong></td><td style="text-align:left;">5.5+</td><td style="text-align:left;">语句/阶段/等待级</td><td style="text-align:left;">实例级</td><td style="text-align:left;">⭐⭐⭐⭐⭐</td></tr><tr><td style="text-align:left;"><strong>sys schema</strong></td><td style="text-align:left;">5.7+</td><td style="text-align:left;">聚合视图</td><td style="text-align:left;">实例级</td><td style="text-align:left;">⭐⭐⭐⭐⭐</td></tr></tbody></table><h3 id="行动清单" tabindex="-1"><a class="header-anchor" href="#行动清单"><span>行动清单</span></a></h3><ol><li><strong>开启慢查询日志</strong>：<code>SET GLOBAL slow_query_log = ON</code>，<code>SET GLOBAL long_query_time = 1</code>，定期用 <code>mysqldumpslow</code> 分析。</li><li><strong>迁移到 Performance Schema</strong>：MySQL 8.0 用户停止使用 Profile，改用 <code>performance_schema</code> 和 <code>sys</code> schema。</li><li><strong>养成 EXPLAIN 习惯</strong>：上线前对核心 SQL 执行 EXPLAIN，确认使用了正确的索引。</li><li><strong>调整 Buffer Pool</strong>：检查 <code>innodb_buffer_pool_size</code>，确保不是默认的 128MB。</li><li><strong>监控锁等待</strong>：定期查询 <code>information_schema.innodb_locks</code> 和 <code>innodb_trx</code>，及时发现锁竞争。</li><li><strong>扩展阅读</strong>：推荐《高性能 MySQL》第 5 章&quot;创建高性能的索引&quot;和第 6 章&quot;查询性能优化&quot;。</li></ol>',6))])}const g=a(i,[["render",p],["__file","performance.html.vue"]]),k=JSON.parse('{"path":"/mysql/performance.html","title":"","lang":"zh-CN","frontmatter":{"description":"引言 MySQL 性能上不去？先查这 5 个瓶颈点。一条慢 SQL，可能卡在执行计划的索引选择、也可能耗在磁盘 I/O、甚至被锁竞争拖垮。你只用 EXPLAIN 看执行计划？如果执行计划没问题但查询依然慢呢？ 本文带你系统学习 MySQL 性能诊断的核心工具和方法，从 CPU、内存、磁盘 I/O、网络到锁竞争，逐一拆解瓶颈定位思路。读完本文你将掌握： ...","head":[["meta",{"property":"og:url","content":"https://vuepress-theme-hope-docs-demo.netlify.app/mysql/performance.html"}],["meta",{"property":"og:site_name","content":"Java八股文网"}],["meta",{"property":"og:description","content":"引言 MySQL 性能上不去？先查这 5 个瓶颈点。一条慢 SQL，可能卡在执行计划的索引选择、也可能耗在磁盘 I/O、甚至被锁竞争拖垮。你只用 EXPLAIN 看执行计划？如果执行计划没问题但查询依然慢呢？ 本文带你系统学习 MySQL 性能诊断的核心工具和方法，从 CPU、内存、磁盘 I/O、网络到锁竞争，逐一拆解瓶颈定位思路。读完本文你将掌握： ..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-04-18T07:28:17.000Z"}],["meta",{"property":"article:author","content":"Mr.Hope"}],["meta",{"property":"article:modified_time","content":"2026-04-18T07:28:17.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2026-04-18T07:28:17.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Mr.Hope\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"引言","slug":"引言","link":"#引言","children":[]},{"level":2,"title":"Profile 配置与开启","slug":"profile-配置与开启","link":"#profile-配置与开启","children":[{"level":3,"title":"开启 Profile 功能","slug":"开启-profile-功能","link":"#开启-profile-功能","children":[]}]},{"level":2,"title":"使用 Profile 分析 SQL 性能","slug":"使用-profile-分析-sql-性能","link":"#使用-profile-分析-sql-性能","children":[]},{"level":2,"title":"MySQL 8.0 中的替代方案","slug":"mysql-8-0-中的替代方案","link":"#mysql-8-0-中的替代方案","children":[{"level":3,"title":"Performance Schema 常用查询","slug":"performance-schema-常用查询","link":"#performance-schema-常用查询","children":[]}]},{"level":2,"title":"性能瓶颈诊断决策树","slug":"性能瓶颈诊断决策树","link":"#性能瓶颈诊断决策树","children":[]},{"level":2,"title":"生产环境避坑指南","slug":"生产环境避坑指南","link":"#生产环境避坑指南","children":[]},{"level":2,"title":"总结","slug":"总结","link":"#总结","children":[{"level":3,"title":"行动清单","slug":"行动清单","link":"#行动清单","children":[]}]}],"git":{"createdTime":1745907928000,"updatedTime":1776497297000,"contributors":[{"name":"Yideng","email":"oointer@163.com","commits":2}]},"readingTime":{"minutes":5.47,"words":1640},"filePathRelative":"mysql/performance.md","localizedDate":"2025年4月29日","autoDesc":true}');export{g as comp,k as data};
